operations.body:
query GetAllProducts {
  searchProducts {
    id
    title
    description
    category
    variants {
      id
      colorway
      price
      size
    }
  }
}

query GetProductById($productId: ID!) {
  product(id: $productId) {
    id
    title
    description
    category
    variants {
      id
      colorway
      price
      size
    }
  }
}

query GetAllOrders {
  orders {
    id
    buyerId
    status
    placedAt
    items {
      quantity
      unitPrice
      variant {
        id
      }
    }
  }
}

query GetOrderWithDelivery($orderId: ID!) {
  order(id: $orderId) {
    id
    buyerId
    status
    placedAt
    estimatedDelivery
    items {
      quantity
      unitPrice
    }
  }
}
